// Convert Markdown to HTML for WordPress post content
const payload = $json.article;
const clientName = $json.clientName;
const telegramChatId = $json.telegramChatId;

function mdToHtml(md) {
  if (typeof md !== 'string') return '';
  return md
    .replace(/^## (.*$)/gim, '<h2>$1</h2>')
    .replace(/^### (.*$)/gim, '<h3>$1</h3>')
    .replace(/^\* (.*$)/gim, '<li>$1</li>')
    .replace(/\*\*(.*)\*\*/gim, '<strong>$1</strong>')
    .replace(/\*(.*)\*/gim, '<em>$1</em>')
    .split(/\r?\n/)
    .map(line => {
      const l = line.trim();
      if (!l) return '';
      if (l.startsWith('<h') || l.startsWith('<li')) return l;
      return `<p>${l}</p>`;
    })
    .filter(Boolean)
    .join('\n');
}

return [{
  json: {
    clientName,
    telegramChatId,
    keyword: payload.primaryKeyword,
    title: payload.title,
    wpPostPayload: {
      title: payload.title,
      slug: payload.slug,
      excerpt: payload.excerpt,
      content: mdToHtml(payload.bodyMarkdown),
      status: "draft"
    }
  }
}];

const res = $('Publish WordPress Draft').item.json;
const clientName = $('Schema WordPress').item.json.clientName;
const telegramChatId = $('Schema WordPress').item.json.telegramChatId;
const keyword = $('Schema WordPress').item.json.keyword;
const title = $('Schema WordPress').item.json.title;

// WP response contains edit links under wp-admin
const draftEditUrl = `https://3ourasia.id/wp-admin/post.php?post=${res.id}&action=edit`;

return [{
  json: {
    clientName,
    telegramChatId,
    draftEditUrl,
    keyword,
    title,
    status: "success"
  }
}];
